export const bg_48_default =
  "data:image/png;base64,";
export const bg_96_default =
  "data:image/png;base64,";

export function calculateAlphaMap(bgCaptureImageData: ImageData) {
  const { width, height, data } = bgCaptureImageData;
  const alphaMap = new Float32Array(width * height);
  for (let i = 0; i < alphaMap.length; i++) {
    const idx = i * 4;
    const r = data[idx];
    const g = data[idx + 1];
    const b = data[idx + 2];
    const maxChannel = Math.max(r, g, b);
    alphaMap[i] = maxChannel / 255;
  }
  return alphaMap;
}

const ALPHA_NOISE_FLOOR = 3 / 255;
const ALPHA_THRESHOLD = 2e-3;
const MAX_ALPHA = 0.99;
const LOGO_VALUE = 255;

export function removeWatermark(
  imageData: ImageData,
  alphaMap: Float32Array,
  position: { x: number; y: number; width: number; height: number },
  options: any = {},
) {
  const { x, y, width, height } = position;
  const alphaGain =
    Number.isFinite(options.alphaGain) && options.alphaGain > 0
      ? options.alphaGain
      : 1;
  const layers = options.layers || 1;

  for (let row = 0; row < height; row++) {
    for (let col = 0; col < width; col++) {
      const imgIdx = ((y + row) * imageData.width + (x + col)) * 4;
      const alphaIdx = row * width + col;
      const baseAlpha = alphaMap[alphaIdx];

      // Calculate effective alpha for multiple overlapping watermarks
      const rawAlpha = 1 - Math.pow(1 - baseAlpha, layers);

      const signalAlpha = Math.max(0, rawAlpha - ALPHA_NOISE_FLOOR) * alphaGain;
      if (signalAlpha < ALPHA_THRESHOLD) {
        continue;
      }
      const alpha = Math.min(rawAlpha * alphaGain, MAX_ALPHA);
      const oneMinusAlpha = 1 - alpha;
      for (let c = 0; c < 3; c++) {
        const watermarked = imageData.data[imgIdx + c];
        const original = (watermarked - alpha * LOGO_VALUE) / oneMinusAlpha;
        imageData.data[imgIdx + c] = Math.max(
          0,
          Math.min(255, Math.round(original)),
        );
      }
    }
  }
}

export function detectWatermarkConfig(imageWidth: number, imageHeight: number) {
  if (imageWidth > 1024 && imageHeight > 1024) {
    return {
      logoSize: 96,
      marginRight: 64,
      marginBottom: 64,
    };
  }
  return {
    logoSize: 48,
    marginRight: 32,
    marginBottom: 32,
  };
}

export function calculateWatermarkPosition(
  imageWidth: number,
  imageHeight: number,
  config: any,
) {
  const { logoSize, marginRight, marginBottom } = config;
  return {
    x: imageWidth - marginRight - logoSize,
    y: imageHeight - marginBottom - logoSize,
    width: logoSize,
    height: logoSize,
  };
}

export function interpolateAlphaMap(
  sourceAlpha: Float32Array,
  sourceSize: number,
  targetSize: number,
) {
  if (targetSize <= 0) return new Float32Array(0);
  if (sourceSize === targetSize) return new Float32Array(sourceAlpha);
  const out = new Float32Array(targetSize * targetSize);
  const scale = (sourceSize - 1) / Math.max(1, targetSize - 1);
  for (let y = 0; y < targetSize; y++) {
    const sy = y * scale;
    const y0 = Math.floor(sy);
    const y1 = Math.min(sourceSize - 1, y0 + 1);
    const fy = sy - y0;
    for (let x = 0; x < targetSize; x++) {
      const sx = x * scale;
      const x0 = Math.floor(sx);
      const x1 = Math.min(sourceSize - 1, x0 + 1);
      const fx = sx - x0;
      const p00 = sourceAlpha[y0 * sourceSize + x0];
      const p10 = sourceAlpha[y0 * sourceSize + x1];
      const p01 = sourceAlpha[y1 * sourceSize + x0];
      const p11 = sourceAlpha[y1 * sourceSize + x1];
      const top = p00 + (p10 - p00) * fx;
      const bottom = p01 + (p11 - p01) * fx;
      out[y * targetSize + x] = top + (bottom - top) * fy;
    }
  }
  return out;
}

export function createRuntimeCanvas(width: number, height: number) {
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  return canvas;
}

export function getCanvasContext2D(canvas: HTMLCanvasElement) {
  const ctx = canvas.getContext("2d", { willReadFrequently: true });
  if (!ctx) {
    throw new Error("Failed to get 2D canvas context");
  }
  return ctx;
}

export async function loadBackgroundCapture(source: string) {
  const image = new Image();
  image.src = source;
  await image.decode();
  return image;
}

export class WatermarkEngine {
  bgCaptures: any;
  alphaMaps: any;

  constructor(bgCaptures: any) {
    this.bgCaptures = bgCaptures;
    this.alphaMaps = {};
  }

  static async create() {
    const [bg48, bg96] = await Promise.all([
      loadBackgroundCapture(bg_48_default),
      loadBackgroundCapture(bg_96_default),
    ]);
    return new WatermarkEngine({ bg48, bg96 });
  }

  async getAlphaMap(size: number) {
    if (size !== 48 && size !== 96) {
      if (this.alphaMaps[size]) return this.alphaMaps[size];
      const alpha96 = await this.getAlphaMap(96);
      const interpolated = interpolateAlphaMap(alpha96, 96, size);
      this.alphaMaps[size] = interpolated;
      return interpolated;
    }
    if (this.alphaMaps[size]) {
      return this.alphaMaps[size];
    }
    const bgImage = size === 48 ? this.bgCaptures.bg48 : this.bgCaptures.bg96;
    const canvas = createRuntimeCanvas(size, size);
    const ctx = getCanvasContext2D(canvas);
    ctx.drawImage(bgImage, 0, 0);
    const imageData = ctx.getImageData(0, 0, size, size);
    const alphaMap = calculateAlphaMap(imageData);
    this.alphaMaps[size] = alphaMap;
    return alphaMap;
  }

  async removeWatermarkFromImage(
    image: HTMLImageElement | HTMLCanvasElement,
    options: any = {},
  ) {
    const canvas = createRuntimeCanvas(image.width, image.height);
    const ctx = getCanvasContext2D(canvas);
    ctx.drawImage(image, 0, 0);
    const originalImageData = ctx.getImageData(
      0,
      0,
      canvas.width,
      canvas.height,
    );
    const config = detectWatermarkConfig(canvas.width, canvas.height);
    const position = calculateWatermarkPosition(
      canvas.width,
      canvas.height,
      config,
    );
    const alphaMap = await this.getAlphaMap(config.logoSize);

    // Apply removal with mathematically correct multi-layer handling
    removeWatermark(originalImageData, alphaMap, position, options);

    ctx.putImageData(originalImageData, 0, 0);
    return canvas;
  }
}
